window.SQL_EXAMPLES = [{"cat":"select","title":"SELECT أعمدة محددة","level":"مبتدئ","concept":{"ar":"اختيار أعمدة معينة من جدول","en":"Selecting specific columns"},"sql":"SELECT first_name, salary\nFROM employees;","output":"FIRST_NAME   SALARY\nSara         6200\nOmar         4100","explain":{"ar":"يعرض SELECT الأعمدة المطلوبة فقط بدل كل الجدول.","en":"SELECT returns only the requested columns instead of the whole table."},"mistake":{"ar":"كتابة SELECT * دائمًا حتى عند الحاجة لعمودين فقط يهدر الأداء.","en":"Always using SELECT * when only two columns are needed wastes performance."}},{"cat":"select","title":"WHERE بشرط رقمي","level":"مبتدئ","concept":{"ar":"تصفية الصفوف بشرط","en":"Filtering rows with a condition"},"sql":"SELECT first_name, salary\nFROM employees\nWHERE salary > 5000;","output":"FIRST_NAME   SALARY\nSara         6200","explain":{"ar":"WHERE يستبعد أي صف لا يحقق الشرط قبل عرض النتيجة.","en":"WHERE excludes any row that fails the condition before showing results."},"mistake":{"ar":"استخدام = بدل > عند البحث عن نطاق يعطي نتيجة غير كاملة.","en":"Using = instead of > when searching a range gives incomplete results."}},{"cat":"select","title":"ORDER BY تصاعدي وتنازلي","level":"مبتدئ","concept":{"ar":"ترتيب النتائج","en":"Ordering results"},"sql":"SELECT first_name, salary\nFROM employees\nORDER BY salary DESC;","output":"FIRST_NAME   SALARY\nSara         6200\nOmar         4100","explain":{"ar":"DESC يرتب من الأكبر للأصغر، وASC (الافتراضي) من الأصغر للأكبر.","en":"DESC sorts largest to smallest; ASC (default) sorts smallest to largest."},"mistake":{"ar":"نسيان DESC عند طلب الأعلى راتبًا أولًا يعطي ترتيبًا معكوسًا.","en":"Forgetting DESC when the highest salary should appear first reverses the order."}},{"cat":"select","title":"DISTINCT لإزالة التكرار","level":"مبتدئ","concept":{"ar":"عرض قيم فريدة فقط","en":"Showing only unique values"},"sql":"SELECT DISTINCT department_id\nFROM employees;","output":"DEPARTMENT_ID\n10\n20\n30","explain":{"ar":"DISTINCT يحذف الصفوف المكررة من النتيجة النهائية فقط.","en":"DISTINCT removes duplicate rows only from the final result."},"mistake":{"ar":"DISTINCT لا يمنع التكرار في الجدول نفسه، فقط في عرض النتيجة.","en":"DISTINCT does not prevent duplicates in the table, only in the displayed result."}},{"cat":"select","title":"Alias لتسمية الأعمدة","level":"متوسط","concept":{"ar":"إعطاء اسم مؤقت لعمود أو جدول","en":"Giving a temporary name to a column or table"},"sql":"SELECT first_name AS \"Name\", salary AS \"Monthly Salary\"\nFROM employees;","output":"Name    Monthly Salary\nSara    6200","explain":{"ar":"AS يجعل عنوان العمود أوضح للقارئ دون تغيير البيانات.","en":"AS makes the column header clearer without changing the data."},"mistake":{"ar":"نسيان علامات الاقتباس مع اسم يحتوي مسافة يسبب خطأ Syntax.","en":"Forgetting quotes around a name with a space causes a syntax error."}},{"cat":"select","title":"عوامل المقارنة","level":"مبتدئ","concept":{"ar":"استخدام =, !=, <, > معًا","en":"Using =, !=, <, > together"},"sql":"SELECT first_name, department_id\nFROM employees\nWHERE department_id != 10;","output":"FIRST_NAME   DEPARTMENT_ID\nOmar         20","explain":{"ar":"!= يستبعد قيمة محددة ويُبقي كل ما عداها.","en":"!= excludes one value and keeps everything else."},"mistake":{"ar":"الخلط بين != و<> رغم أنهما متكافئان في Oracle قد يربك المبتدئ فقط لا أكثر.","en":"Confusing != and <> is harmless in Oracle since both are equivalent."}},{"cat":"select","title":"عوامل منطقية AND/OR","level":"متوسط","concept":{"ar":"دمج أكثر من شرط","en":"Combining multiple conditions"},"sql":"SELECT first_name, salary, department_id\nFROM employees\nWHERE department_id = 10 AND salary > 4000;","output":"FIRST_NAME   SALARY   DEPARTMENT_ID\nSara         6200     10","explain":{"ar":"AND يتطلب تحقق الشرطين معًا، بينما OR يكفي تحقق أحدهما.","en":"AND requires both conditions; OR requires only one."},"mistake":{"ar":"استخدام OR بدل AND يوسّع النتيجة أكثر من المطلوب.","en":"Using OR instead of AND widens the result more than intended."}},{"cat":"select","title":"BETWEEN لنطاق قيم","level":"متوسط","concept":{"ar":"التحقق من وقوع القيمة بين حدين","en":"Checking if a value falls within a range"},"sql":"SELECT first_name, salary\nFROM employees\nWHERE salary BETWEEN 4000 AND 6500;","output":"FIRST_NAME   SALARY\nSara         6200\nOmar         4100","explain":{"ar":"BETWEEN شامل للحدين نفسيهما (Inclusive).","en":"BETWEEN is inclusive of both boundary values."},"mistake":{"ar":"نسيان أن الحدين داخلان في النتيجة قد يعطي عناصر غير متوقعة عند حافة النطاق.","en":"Forgetting that both edges are included can surprise you at range boundaries."}},{"cat":"select","title":"IN لقائمة قيم","level":"متوسط","concept":{"ar":"مطابقة القيمة مع مجموعة","en":"Matching a value against a set"},"sql":"SELECT first_name, department_id\nFROM employees\nWHERE department_id IN (10,30);","output":"FIRST_NAME   DEPARTMENT_ID\nSara         10","explain":{"ar":"IN تختصر سلسلة طويلة من OR على نفس العمود.","en":"IN shortens a long chain of OR on the same column."},"mistake":{"ar":"استخدام = مع أكثر من قيمة يسبب خطأ؛ IN هي الحل الصحيح.","en":"Using = with more than one value causes an error; IN is the correct fix."}},{"cat":"select","title":"LIKE للبحث النصي","level":"متوسط","concept":{"ar":"مطابقة نمط في نص","en":"Matching a text pattern"},"sql":"SELECT first_name\nFROM employees\nWHERE first_name LIKE 'S%';","output":"FIRST_NAME\nSara","explain":{"ar":"% تعني أي عدد من الأحرف، و_ تعني حرفًا واحدًا فقط.","en":"% means any number of characters; _ means exactly one character."},"mistake":{"ar":"نسيان % يجعل LIKE يبحث عن تطابق كامل فقط وليس بحثًا جزئيًا.","en":"Forgetting % makes LIKE search for an exact match only, not a partial one."}},{"cat":"ddl","title":"CREATE TABLE أساسي","level":"مبتدئ","concept":{"ar":"إنشاء جدول جديد ببنية أعمدة محددة","en":"Creating a new table with defined columns"},"sql":"CREATE TABLE students (\n  student_id NUMBER PRIMARY KEY,\n  full_name VARCHAR2(60) NOT NULL,\n  gpa NUMBER(3,2)\n);","output":"Table STUDENTS created.","explain":{"ar":"كل عمود يحدد نوعه، وPRIMARY KEY يمنع تكرار student_id.","en":"Each column defines its type, and PRIMARY KEY prevents duplicate student_id values."},"mistake":{"ar":"نسيان تحديد نوع البيانات لعمود يسبب خطأ Syntax مباشرة.","en":"Forgetting a column data type causes an immediate syntax error."}},{"cat":"ddl","title":"ALTER TABLE ADD","level":"مبتدئ","concept":{"ar":"إضافة عمود جديد لجدول موجود","en":"Adding a new column to an existing table"},"sql":"ALTER TABLE students\nADD email VARCHAR2(100);","output":"Table STUDENTS altered.","explain":{"ar":"العمود الجديد يُضاف بقيمة NULL لكل الصفوف الموجودة سابقًا.","en":"The new column is added as NULL for all existing rows."},"mistake":{"ar":"إضافة عمود NOT NULL بدون DEFAULT على جدول يحتوي بيانات يفشل التنفيذ.","en":"Adding a NOT NULL column without DEFAULT on a populated table fails."}},{"cat":"ddl","title":"ALTER TABLE MODIFY","level":"متوسط","concept":{"ar":"تغيير نوع أو حجم عمود موجود","en":"Changing an existing column type or size"},"sql":"ALTER TABLE students\nMODIFY full_name VARCHAR2(100);","output":"Table STUDENTS altered.","explain":{"ar":"MODIFY يغيّر خصائص العمود دون حذف بياناته.","en":"MODIFY changes column properties without deleting its data."},"mistake":{"ar":"تصغير حجم عمود يحتوي بيانات أطول من الحجم الجديد يسبب خطأ.","en":"Shrinking a column below its existing data length causes an error."}},{"cat":"ddl","title":"ALTER TABLE DROP COLUMN","level":"متوسط","concept":{"ar":"حذف عمود من جدول","en":"Dropping a column from a table"},"sql":"ALTER TABLE students\nDROP COLUMN email;","output":"Table STUDENTS altered.","explain":{"ar":"حذف العمود يزيل بياناته نهائيًا من كل الصفوف.","en":"Dropping the column permanently removes its data from every row."},"mistake":{"ar":"حذف عمود مستخدم في View أو Constraint قد يفشل حتى تُزال التبعية أولًا.","en":"Dropping a column used in a view or constraint may fail until the dependency is removed."}},{"cat":"ddl","title":"ADD CONSTRAINT","level":"متوسط","concept":{"ar":"إضافة قيد على جدول قائم","en":"Adding a constraint to an existing table"},"sql":"ALTER TABLE students\nADD CONSTRAINT gpa_ck CHECK (gpa BETWEEN 0 AND 4);","output":"Table STUDENTS altered.","explain":{"ar":"CHECK يمنع إدخال قيمة gpa خارج النطاق المسموح مستقبلًا.","en":"CHECK prevents inserting a gpa value outside the allowed range going forward."},"mistake":{"ar":"إضافة قيد يخالف بيانات موجودة فعليًا يفشل التنفيذ فورًا.","en":"Adding a constraint that existing data already violates fails immediately."}},{"cat":"ddl","title":"DROP CONSTRAINT وتعطيله","level":"متقدم","concept":{"ar":"حذف أو تعطيل قيد دون حذفه نهائيًا","en":"Dropping or disabling a constraint without deleting it permanently"},"sql":"ALTER TABLE students DISABLE CONSTRAINT gpa_ck;\nALTER TABLE students ENABLE CONSTRAINT gpa_ck;","output":"Table STUDENTS altered. (x2)","explain":{"ar":"DISABLE يوقف تفعيل القيد مؤقتًا، وENABLE يعيده دون إعادة إنشائه.","en":"DISABLE temporarily suspends the constraint; ENABLE reactivates it without recreating it."},"mistake":{"ar":"نسيان إعادة ENABLE يترك الجدول بلا حماية من بيانات غير صالحة.","en":"Forgetting to ENABLE again leaves the table unprotected from invalid data."}},{"cat":"ddl","title":"DROP TABLE","level":"متوسط","concept":{"ar":"حذف جدول بالكامل مع بنيته","en":"Deleting an entire table with its structure"},"sql":"DROP TABLE students;","output":"Table STUDENTS dropped.","explain":{"ar":"DROP يحذف الجدول وبياناته وبنيته من قاعدة البيانات نهائيًا.","en":"DROP permanently removes the table, its data, and its structure."},"mistake":{"ar":"لا يمكن التراجع عن DROP TABLE بسهولة كما في DELETE مع Transaction.","en":"DROP TABLE cannot be easily undone the way DELETE can within a transaction."}},{"cat":"ddl","title":"TRUNCATE TABLE","level":"متوسط","concept":{"ar":"إفراغ جدول من كل صفوفه بسرعة","en":"Quickly emptying all rows from a table"},"sql":"TRUNCATE TABLE students;","output":"Table STUDENTS truncated.","explain":{"ar":"TRUNCATE أسرع من DELETE بلا شرط، لكنه لا يقبل WHERE ويصعب التراجع عنه.","en":"TRUNCATE is faster than an unconditional DELETE, but it accepts no WHERE and is hard to undo."},"mistake":{"ar":"الاعتقاد بأن TRUNCATE يحذف الجدول نفسه خطأ؛ هو يفرغه فقط ويبقي بنيته.","en":"Thinking TRUNCATE deletes the table itself is wrong; it only empties it and keeps the structure."}},{"cat":"ddl","title":"RENAME","level":"مبتدئ","concept":{"ar":"تغيير اسم كائن في قاعدة البيانات","en":"Renaming a database object"},"sql":"RENAME students TO learners;","output":"Table renamed.","explain":{"ar":"RENAME يغيّر الاسم فقط دون التأثير على البيانات أو الأعمدة.","en":"RENAME changes only the name without affecting data or columns."},"mistake":{"ar":"نسيان تحديث أسماء الجداول في Views أو التطبيقات بعد الإعادة تسمية.","en":"Forgetting to update table names in views or applications after renaming."}},{"cat":"ddl","title":"COMMENT ON","level":"متقدم","concept":{"ar":"إضافة وصف توثيقي لجدول أو عمود","en":"Adding a documentation comment to a table or column"},"sql":"COMMENT ON TABLE learners IS 'Stores registered learners';\nCOMMENT ON COLUMN learners.gpa IS 'Grade point average 0-4';","output":"Comment added.","explain":{"ar":"التعليقات توثيقية فقط ولا تؤثر على تنفيذ الاستعلامات.","en":"Comments are documentation only and do not affect query execution."},"mistake":{"ar":"نسيان التعليقات على أعمدة غامضة الاسم يصعّب الصيانة لاحقًا لفريق آخر.","en":"Skipping comments on ambiguously named columns makes later maintenance harder for other teams."}},{"cat":"dml","title":"INSERT سجل واحد","level":"مبتدئ","concept":{"ar":"إضافة صف جديد بكل قيمه","en":"Adding one new row with all its values"},"sql":"INSERT INTO students (student_id, full_name, gpa)\nVALUES (1, 'Lina Al-Amri', 3.8);","output":"1 row created.","explain":{"ar":"تحديد أسماء الأعمدة صراحة يمنع الخلط عند تغيير ترتيب الجدول لاحقًا.","en":"Explicitly listing column names avoids confusion if the table order changes later."},"mistake":{"ar":"عدم تحديد أسماء الأعمدة يجبرك على إدخال القيم بنفس ترتيب الجدول تمامًا.","en":"Omitting column names forces values to match the table exact column order."}},{"cat":"dml","title":"INSERT عدة صفوف","level":"مبتدئ","concept":{"ar":"إضافة أكثر من صف بعملية واحدة","en":"Adding multiple rows in one statement"},"sql":"INSERT ALL\n  INTO students VALUES (2,'Yousef',3.2)\n  INTO students VALUES (3,'Mona',3.9)\nSELECT * FROM dual;","output":"2 rows created.","explain":{"ar":"INSERT ALL في Oracle يسمح بإدخال عدة صفوف بجملة واحدة.","en":"INSERT ALL in Oracle allows inserting multiple rows in a single statement."},"mistake":{"ar":"نسيان SELECT * FROM dual في نهاية الجملة يسبب خطأ Syntax.","en":"Forgetting SELECT * FROM dual at the end causes a syntax error."}},{"cat":"dml","title":"UPDATE بشرط WHERE","level":"مبتدئ","concept":{"ar":"تعديل قيمة عمود لصفوف محددة","en":"Updating a column value for specific rows"},"sql":"UPDATE students\nSET gpa = 4.0\nWHERE student_id = 1;","output":"1 row updated.","explain":{"ar":"WHERE يحدد بالضبط الصف الذي سيتغير دون المساس بالباقي.","en":"WHERE precisely targets the row that changes, leaving the rest untouched."},"mistake":{"ar":"كتابة WHERE بشرط خاطئ قد يعدّل صفوفًا غير مقصودة.","en":"Writing WHERE with the wrong condition may update unintended rows."}},{"cat":"dml","title":"خطر UPDATE بدون WHERE","level":"متقدم","concept":{"ar":"توضيح ما يحدث عند حذف شرط التحديث","en":"Showing what happens when the update condition is missing"},"sql":"UPDATE students\nSET gpa = 0;","output":"3 rows updated. -- كل الصفوف تغيّرت!","explain":{"ar":"بدون WHERE يطبَّق SET على كل صف في الجدول دفعة واحدة.","en":"Without WHERE, SET applies to every row in the table at once."},"mistake":{"ar":"هذا من أخطر الأخطاء الشائعة؛ راجع الشرط قبل تنفيذ UPDATE دائمًا.","en":"This is one of the most dangerous common mistakes; always review the condition before running UPDATE."}},{"cat":"dml","title":"DELETE بشرط WHERE","level":"مبتدئ","concept":{"ar":"حذف صفوف محددة فقط","en":"Deleting only specific rows"},"sql":"DELETE FROM students\nWHERE gpa < 2.0;","output":"0 rows deleted.","explain":{"ar":"DELETE مع WHERE يحذف فقط الصفوف المطابقة للشرط.","en":"DELETE with WHERE removes only the rows matching the condition."},"mistake":{"ar":"التأكد أولًا بـSELECT بنفس الشرط قبل تنفيذ DELETE فعليًا يقي من الأخطاء.","en":"Testing the same condition first with SELECT before running DELETE prevents mistakes."}},{"cat":"dml","title":"خطر DELETE بدون WHERE","level":"متقدم","concept":{"ar":"توضيح خطر حذف الجدول بالكامل بالخطأ","en":"Showing the danger of accidentally deleting an entire table"},"sql":"DELETE FROM students;","output":"3 rows deleted. -- الجدول أصبح فارغًا","explain":{"ar":"بدون WHERE يُحذف كل صف، لكن بنية الجدول تبقى (خلافًا لـDROP).","en":"Without WHERE every row is removed, though the table structure remains (unlike DROP)."},"mistake":{"ar":"الاعتماد على COMMIT التلقائي دون مراجعة قد يمنع التراجع عن الحذف.","en":"Relying on automatic commit without review may prevent undoing the deletion."}},{"cat":"dml","title":"MERGE — مزامنة جدولين","level":"متقدم","concept":{"ar":"تحديث الموجود وإدخال الجديد بعملية واحدة","en":"Updating existing rows and inserting new ones in a single statement"},"sql":"MERGE INTO students s\nUSING students_staging n\nON (s.student_id = n.student_id)\nWHEN MATCHED THEN UPDATE SET s.gpa = n.gpa\nWHEN NOT MATCHED THEN INSERT (student_id, full_name, gpa)\n  VALUES (n.student_id, n.full_name, n.gpa);","output":"MERGE completed.","explain":{"ar":"WHEN MATCHED يحدّث الصف الموجود، وWHEN NOT MATCHED يدرج صفًا جديدًا.","en":"WHEN MATCHED updates the existing row; WHEN NOT MATCHED inserts a new one."},"mistake":{"ar":"نسيان شرط ON الصحيح يجعل MERGE يقارن كل الصفوف ببعضها بشكل خاطئ.","en":"Forgetting the correct ON condition makes MERGE compare all rows incorrectly."}},{"cat":"dml","title":"INSERT من نتيجة استعلام","level":"متوسط","concept":{"ar":"نسخ نتيجة SELECT إلى جدول آخر","en":"Copying a SELECT result into another table"},"sql":"INSERT INTO honor_students (student_id, full_name)\nSELECT student_id, full_name\nFROM students\nWHERE gpa >= 3.5;","output":"2 rows created.","explain":{"ar":"هذا الشكل من INSERT يدمج SELECT وINSERT لنسخ بيانات مصفّاة مباشرة.","en":"This form of INSERT combines SELECT and INSERT to copy filtered data directly."},"mistake":{"ar":"عدم تطابق عدد أو نوع الأعمدة بين SELECT والجدول الهدف يسبب خطأ.","en":"Mismatched column count or types between the SELECT and target table cause an error."}},{"cat":"dml","title":"UPDATE بقيمة من جدول آخر","level":"متقدم","concept":{"ar":"تحديث عمود بالاعتماد على جدول مرتبط","en":"Updating a column based on a related table"},"sql":"UPDATE employees e\nSET department_id = (\n  SELECT department_id FROM departments WHERE department_name='Sales'\n)\nWHERE e.employee_id = 105;","output":"1 row updated.","explain":{"ar":"Subquery داخل SET يجلب قيمة واحدة فقط ليستخدمها UPDATE.","en":"A subquery inside SET fetches a single value for UPDATE to use."},"mistake":{"ar":"إذا أعاد الـSubquery أكثر من صف، يفشل UPDATE بخطأ single-row subquery.","en":"If the subquery returns more than one row, UPDATE fails with a single-row subquery error."}},{"cat":"dml","title":"DELETE بشرط مرتبط بجدول آخر","level":"متقدم","concept":{"ar":"حذف صفوف بناءً على جدول مرتبط","en":"Deleting rows based on a related table"},"sql":"DELETE FROM employees\nWHERE department_id IN (\n  SELECT department_id FROM departments WHERE department_name='Closed'\n);","output":"0 rows deleted.","explain":{"ar":"الشرط هنا لا يعتمد على قيمة ثابتة، بل على نتيجة استعلام آخر.","en":"The condition here relies on another query result rather than a fixed value."},"mistake":{"ar":"عدم اختبار الـSubquery وحده أولًا قد يخفي نتيجة فارغة أو خاطئة.","en":"Not testing the subquery alone first may hide an empty or wrong result."}},{"cat":"dcl","title":"GRANT صلاحية نظام","level":"مبتدئ","concept":{"ar":"منح مستخدم القدرة على الاتصال أو الإنشاء","en":"Granting a user the ability to connect or create"},"sql":"GRANT CREATE SESSION, CREATE TABLE TO lina;","output":"Grant succeeded.","explain":{"ar":"System Privilege يمنح قدرة عامة غير مرتبطة بجدول معين.","en":"A system privilege grants a general capability not tied to a specific table."},"mistake":{"ar":"منح CREATE TABLE دون CREATE SESSION يمنع المستخدم أصلًا من تسجيل الدخول لاستخدامها.","en":"Granting CREATE TABLE without CREATE SESSION prevents the user from even logging in to use it."}},{"cat":"dcl","title":"GRANT صلاحية على كائن","level":"مبتدئ","concept":{"ar":"منح صلاحية قراءة أو تعديل على جدول محدد","en":"Granting read or modify access on a specific table"},"sql":"GRANT SELECT, INSERT ON students TO lina;","output":"Grant succeeded.","explain":{"ar":"Object Privilege مرتبطة بكائن معين مثل جدول أو View.","en":"An object privilege is tied to a specific object such as a table or view."},"mistake":{"ar":"منح ALL PRIVILEGES دون داعٍ يمنح صلاحيات أوسع مما يحتاجه المستخدم فعليًا.","en":"Granting ALL PRIVILEGES unnecessarily gives broader access than the user actually needs."}},{"cat":"dcl","title":"GRANT مع WITH GRANT OPTION","level":"متقدم","concept":{"ar":"السماح للمستخدم بمنح الصلاحية لغيره","en":"Allowing a user to grant the privilege to others"},"sql":"GRANT SELECT ON students TO lina WITH GRANT OPTION;","output":"Grant succeeded.","explain":{"ar":"WITH GRANT OPTION يعطي lina صلاحية تمرير SELECT لمستخدمين آخرين.","en":"WITH GRANT OPTION lets lina pass the SELECT privilege on to other users."},"mistake":{"ar":"استخدامها بلا حذر يوسّع دائرة من يملك صلاحية الوصول دون رقابة مركزية.","en":"Using it carelessly widens who has access without central control."}},{"cat":"dcl","title":"REVOKE صلاحية","level":"مبتدئ","concept":{"ar":"سحب صلاحية سبق منحها","en":"Withdrawing a previously granted privilege"},"sql":"REVOKE INSERT ON students FROM lina;","output":"Revoke succeeded.","explain":{"ar":"REVOKE يزيل فقط الصلاحية المذكورة، ويترك الباقي كما هو.","en":"REVOKE removes only the stated privilege, leaving the rest untouched."},"mistake":{"ar":"كتابة نوع صلاحية مختلف عمّا مُنح فعليًا لا يزيل شيئًا.","en":"Specifying a different privilege type than what was actually granted removes nothing."}},{"cat":"dcl","title":"فرق System Privilege عن Object Privilege","level":"متوسط","concept":{"ar":"التمييز بين الصلاحيات العامة والخاصة بكائن","en":"Distinguishing general privileges from object-specific ones"},"sql":"GRANT CREATE TABLE TO lina;      -- System\nGRANT SELECT ON students TO lina; -- Object","output":"Grant succeeded. (x2)","explain":{"ar":"System Privilege تتعلق بإجراء عام، وObject Privilege تتعلق بكائن محدد بالاسم.","en":"System privileges relate to a general action; object privileges relate to a specifically named object."},"mistake":{"ar":"الخلط بينهما يؤدي لمنح صلاحية أوسع من اللازم أو أضيق من المطلوب.","en":"Confusing the two leads to granting either broader or narrower access than needed."}},{"cat":"dcl","title":"GRANT SELECT على أعمدة محددة","level":"متقدم","concept":{"ar":"تقييد القراءة على أعمدة معينة فقط","en":"Restricting read access to specific columns only"},"sql":"GRANT SELECT (student_id, full_name) ON students TO lina;","output":"Grant succeeded.","explain":{"ar":"تحديد الأعمدة يمنع الوصول لأعمدة حساسة مثل الرواتب أو كلمات المرور.","en":"Specifying columns prevents access to sensitive ones like salaries or passwords."},"mistake":{"ar":"عدم تحديد الأعمدة يمنح رؤية كاملة للجدول حتى لو لم تكن كل الأعمدة مطلوبة.","en":"Not specifying columns grants full table visibility even when not all columns are needed."}},{"cat":"dcl","title":"REVOKE من عدة مستخدمين","level":"متوسط","concept":{"ar":"سحب صلاحية من أكثر من مستخدم دفعة واحدة","en":"Revoking a privilege from multiple users at once"},"sql":"REVOKE SELECT ON students FROM lina, omar;","output":"Revoke succeeded.","explain":{"ar":"يمكن كتابة أكثر من اسم مستخدم مفصولين بفاصلة في نفس الجملة.","en":"Multiple usernames separated by commas can appear in the same statement."},"mistake":{"ar":"نسيان أحد الأسماء يترك صلاحية الوصول قائمة له دون قصد.","en":"Forgetting a name leaves that user with unintended lingering access."}},{"cat":"dcl","title":"منح صلاحية لكل المستخدمين","level":"متقدم","concept":{"ar":"استخدام PUBLIC لمنح صلاحية للجميع","en":"Using PUBLIC to grant a privilege to everyone"},"sql":"GRANT SELECT ON students TO PUBLIC;","output":"Grant succeeded.","explain":{"ar":"PUBLIC تمنح الصلاحية لكل مستخدم في قاعدة البيانات دفعة واحدة.","en":"PUBLIC grants the privilege to every user in the database at once."},"mistake":{"ar":"استخدام PUBLIC مع بيانات حساسة يخالف مبدأ أقل صلاحية ممكنة.","en":"Using PUBLIC with sensitive data violates the principle of least privilege."}},{"cat":"constraints","title":"PRIMARY KEY","level":"مبتدئ","concept":{"ar":"منع تكرار وفراغ عمود المعرف","en":"Preventing duplicate or empty identifier values"},"sql":"CREATE TABLE courses (\n  course_id NUMBER PRIMARY KEY,\n  title VARCHAR2(60)\n);","output":"Table COURSES created.","explain":{"ar":"كل جدول يجب أن يملك Primary Key يميّز كل صف بشكل فريد.","en":"Every table should have a primary key that uniquely identifies each row."},"mistake":{"ar":"محاولة إدخال course_id مكرر يفشل فورًا برسالة unique constraint violated.","en":"Inserting a duplicate course_id fails immediately with a unique constraint violated error."}},{"cat":"constraints","title":"FOREIGN KEY","level":"مبتدئ","concept":{"ar":"ربط جدول بجدول آخر عبر مفتاح مشترك","en":"Linking one table to another through a shared key"},"sql":"CREATE TABLE enrollments (\n  student_id NUMBER REFERENCES students(student_id),\n  course_id NUMBER REFERENCES courses(course_id)\n);","output":"Table ENROLLMENTS created.","explain":{"ar":"FOREIGN KEY يمنع إدخال قيمة غير موجودة أصلًا في الجدول المرجعي.","en":"A foreign key prevents inserting a value that does not exist in the referenced table."},"mistake":{"ar":"محاولة حذف صف من الجدول الأب مرتبط بصفوف في الجدول الابن يفشل دون ON DELETE CASCADE.","en":"Deleting a parent row linked to child rows fails without ON DELETE CASCADE."}},{"cat":"constraints","title":"NOT NULL","level":"مبتدئ","concept":{"ar":"إجبار العمود على قيمة دائمًا","en":"Forcing a column to always have a value"},"sql":"ALTER TABLE students\nMODIFY full_name VARCHAR2(60) NOT NULL;","output":"Table STUDENTS altered.","explain":{"ar":"NOT NULL يمنع ترك الحقل فارغًا عند الإدخال أو التحديث.","en":"NOT NULL prevents leaving the field empty on insert or update."},"mistake":{"ar":"إضافتها على عمود يحتوي بالفعل قيم NULL موجودة يفشل حتى تُعالَج تلك الصفوف.","en":"Adding it to a column with existing NULL values fails until those rows are fixed."}},{"cat":"constraints","title":"UNIQUE","level":"مبتدئ","concept":{"ar":"منع تكرار قيمة عمود غير المفتاح الأساسي","en":"Preventing duplicate values in a non-primary-key column"},"sql":"ALTER TABLE students\nADD CONSTRAINT email_uq UNIQUE (email);","output":"Table STUDENTS altered.","explain":{"ar":"UNIQUE يسمح بقيمة NULL واحدة أو أكثر، لكنه يمنع تكرار القيم الفعلية.","en":"UNIQUE allows one or more NULLs but prevents duplicate actual values."},"mistake":{"ar":"الخلط بين UNIQUE وPRIMARY KEY رغم أن الجدول يقبل أكثر من عمود UNIQUE.","en":"Confusing UNIQUE with PRIMARY KEY, even though a table can have multiple UNIQUE columns."}},{"cat":"constraints","title":"CHECK","level":"متوسط","concept":{"ar":"فرض شرط منطقي على قيم العمود","en":"Enforcing a logical condition on column values"},"sql":"ALTER TABLE students\nADD CONSTRAINT gpa_range_ck CHECK (gpa BETWEEN 0 AND 4);","output":"Table STUDENTS altered.","explain":{"ar":"CHECK يرفض أي قيمة تخالف الشرط المكتوب داخل الأقواس.","en":"CHECK rejects any value that violates the condition written inside the parentheses."},"mistake":{"ar":"كتابة شرط CHECK يعتمد على عمود آخر لم يعد له وجود بعد تعديل الجدول.","en":"Writing a CHECK condition that depends on a column no longer present after altering the table."}},{"cat":"constraints","title":"DEFAULT","level":"مبتدئ","concept":{"ar":"قيمة تلقائية عند عدم إدخال العمود","en":"An automatic value when the column is not provided"},"sql":"ALTER TABLE students\nADD enrolled_on DATE DEFAULT SYSDATE;","output":"Table STUDENTS altered.","explain":{"ar":"DEFAULT يملأ القيمة تلقائيًا إن لم يحددها المستخدم أثناء INSERT.","en":"DEFAULT fills the value automatically if the user does not specify it during INSERT."},"mistake":{"ar":"الاعتقاد أن DEFAULT يمنع إدخال قيمة أخرى صراحة؛ يمكن تجاوزه بسهولة.","en":"Believing DEFAULT blocks explicitly entering another value; it can easily be overridden."}},{"cat":"constraints","title":"مفتاح أساسي مركب","level":"متقدم","concept":{"ar":"استخدام أكثر من عمود معًا كمفتاح أساسي","en":"Using more than one column together as a primary key"},"sql":"CREATE TABLE enrollments (\n  student_id NUMBER,\n  course_id NUMBER,\n  CONSTRAINT enr_pk PRIMARY KEY (student_id, course_id)\n);","output":"Table ENROLLMENTS created.","explain":{"ar":"المفتاح المركب يضمن عدم تكرار نفس تركيبة الطالب والمقرر معًا.","en":"A composite key ensures the same student-course combination cannot repeat."},"mistake":{"ar":"تسمية القيد باسم واضح مثل enr_pk تسهّل قراءة الأخطاء لاحقًا؛ إغفال ذلك يصعّب التتبع.","en":"Naming the constraint clearly (e.g. enr_pk) eases debugging later; skipping this makes tracing harder."}},{"cat":"constraints","title":"ON DELETE CASCADE","level":"متقدم","concept":{"ar":"حذف الصفوف التابعة تلقائيًا عند حذف الأصل","en":"Automatically deleting dependent rows when the parent is deleted"},"sql":"ALTER TABLE enrollments\nADD CONSTRAINT enr_stu_fk FOREIGN KEY (student_id)\nREFERENCES students(student_id) ON DELETE CASCADE;","output":"Table ENROLLMENTS altered.","explain":{"ar":"CASCADE يحذف تلقائيًا كل صف في enrollments يشير إلى الطالب المحذوف.","en":"CASCADE automatically deletes every enrollments row referencing the deleted student."},"mistake":{"ar":"استخدامها دون وعي قد يحذف بيانات تابعة أكثر مما توقع المطور.","en":"Using it without care may delete more dependent data than the developer expected."}},{"cat":"constraints","title":"قيد على أكثر من عمود CHECK","level":"متقدم","concept":{"ar":"التحقق من علاقة بين عمودين معًا","en":"Validating a relationship between two columns together"},"sql":"ALTER TABLE courses\nADD CONSTRAINT dates_ck CHECK (end_date > start_date);","output":"Table COURSES altered.","explain":{"ar":"CHECK يمكن أن يقارن بين عمودين في نفس الصف وليس فقط عمود بقيمة ثابتة.","en":"CHECK can compare two columns in the same row, not just one column against a fixed value."},"mistake":{"ar":"اختبار القيد ببيانات حافة (تواريخ متساوية) يكشف سلوكًا غير متوقع أحيانًا.","en":"Testing the constraint with edge-case data (equal dates) sometimes reveals unexpected behavior."}},{"cat":"constraints","title":"تعطيل قيد مؤقتًا لإدخال بيانات تاريخية","level":"متقدم","concept":{"ar":"استخدام DISABLE مؤقتًا ثم ENABLE VALIDATE","en":"Temporarily using DISABLE then ENABLE VALIDATE"},"sql":"ALTER TABLE students DISABLE CONSTRAINT gpa_range_ck;\n-- إدخال بيانات قديمة\nALTER TABLE students ENABLE VALIDATE CONSTRAINT gpa_range_ck;","output":"Table STUDENTS altered. (x2)","explain":{"ar":"ENABLE VALIDATE يتأكد أن كل البيانات الحالية والمستقبلية تحقق الشرط.","en":"ENABLE VALIDATE ensures both existing and future data satisfy the condition."},"mistake":{"ar":"نسيان التحقق بعد إعادة التفعيل قد يترك بيانات قديمة مخالفة للقيد دون علم.","en":"Forgetting to validate after re-enabling may leave old violating data unnoticed."}},{"cat":"objects","title":"CREATE VIEW بسيط","level":"مبتدئ","concept":{"ar":"حفظ استعلام كعرض قابل لإعادة الاستخدام","en":"Saving a query as a reusable view"},"sql":"CREATE VIEW active_students AS\nSELECT student_id, full_name\nFROM students\nWHERE gpa >= 2.0;","output":"View created.","explain":{"ar":"الـView لا يخزّن بيانات، بل يشغّل الاستعلام نفسه في كل استخدام.","en":"A view stores no data; it re-runs the same query every time it is used."},"mistake":{"ar":"الاعتقاد أن View نسخة منفصلة من البيانات؛ هي فقط استعلام محفوظ.","en":"Assuming a view is a separate data copy; it is only a saved query."}},{"cat":"objects","title":"CREATE OR REPLACE VIEW","level":"متوسط","concept":{"ar":"تعديل تعريف عرض موجود دون حذفه","en":"Modifying an existing view definition without dropping it"},"sql":"CREATE OR REPLACE VIEW active_students AS\nSELECT student_id, full_name, gpa\nFROM students\nWHERE gpa >= 2.5;","output":"View created.","explain":{"ar":"OR REPLACE يحدّث تعريف الـView مباشرة دون التأثير على الصلاحيات الممنوحة عليه.","en":"OR REPLACE updates the view definition directly without affecting privileges already granted on it."},"mistake":{"ar":"نسيان OR REPLACE يجبرك على DROP ثم CREATE، فتفقد صلاحيات ممنوحة سابقًا.","en":"Forgetting OR REPLACE forces a DROP then CREATE, losing previously granted privileges."}},{"cat":"objects","title":"WITH CHECK OPTION","level":"متقدم","concept":{"ar":"منع إدخال صفوف عبر View لا تطابق شرطها","en":"Preventing rows inserted via a view from violating its condition"},"sql":"CREATE VIEW high_gpa AS\nSELECT * FROM students WHERE gpa >= 3.5\nWITH CHECK OPTION;","output":"View created.","explain":{"ar":"أي INSERT أو UPDATE عبر هذا الـView يجب أن يحقق شرط gpa >= 3.5 وإلا رُفض.","en":"Any INSERT or UPDATE through this view must satisfy gpa >= 3.5 or it is rejected."},"mistake":{"ar":"بدون WITH CHECK OPTION يمكن إدخال صف عبر الـView لا يظهر فيه لاحقًا.","en":"Without WITH CHECK OPTION, a row can be inserted through the view that then never appears in it."}},{"cat":"objects","title":"WITH READ ONLY","level":"متوسط","concept":{"ar":"منع أي تعديل بيانات عبر View","en":"Preventing any data modification through a view"},"sql":"CREATE VIEW gpa_report AS\nSELECT student_id, gpa FROM students\nWITH READ ONLY;","output":"View created.","explain":{"ar":"هذا الـView مخصص للعرض فقط، ولا يقبل أي INSERT أو UPDATE أو DELETE.","en":"This view is display-only and rejects any INSERT, UPDATE, or DELETE."},"mistake":{"ar":"محاولة UPDATE عبر View للقراءة فقط تعطي خطأ ORA-01733 مباشرة.","en":"Attempting UPDATE through a read-only view directly gives an ORA-01733 error."}},{"cat":"objects","title":"CREATE SEQUENCE","level":"مبتدئ","concept":{"ar":"توليد أرقام تسلسلية تلقائية","en":"Generating automatic sequential numbers"},"sql":"CREATE SEQUENCE course_seq\nSTART WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;","output":"Sequence created.","explain":{"ar":"Sequence يولّد رقمًا جديدًا في كل استدعاء لـNEXTVAL، بمعزل عن أي جدول.","en":"A sequence generates a new number on each NEXTVAL call, independent of any table."},"mistake":{"ar":"استخدام CURRVAL قبل استدعاء NEXTVAL مرة واحدة على الأقل في الجلسة يسبب خطأ.","en":"Using CURRVAL before calling NEXTVAL at least once in the session causes an error."}},{"cat":"objects","title":"استخدام Sequence مع INSERT","level":"متوسط","concept":{"ar":"توليد مفتاح أساسي تلقائي عند الإدخال","en":"Auto-generating a primary key on insert"},"sql":"INSERT INTO courses (course_id, title)\nVALUES (course_seq.NEXTVAL, 'SQL Basics');","output":"1 row created.","explain":{"ar":"NEXTVAL يعطي رقمًا جديدًا فريدًا في كل مرة، مناسبًا كمفتاح أساسي.","en":"NEXTVAL gives a new unique number each time, suitable as a primary key."},"mistake":{"ar":"استدعاء NEXTVAL أكثر من مرة في نفس الجملة عن طريق الخطأ يهدر أرقامًا من التسلسل.","en":"Accidentally calling NEXTVAL more than once in the same statement wastes sequence numbers."}},{"cat":"objects","title":"ALTER SEQUENCE","level":"متقدم","concept":{"ar":"تعديل خصائص Sequence بعد إنشائه","en":"Modifying a sequence properties after creation"},"sql":"ALTER SEQUENCE course_seq\nINCREMENT BY 5 MAXVALUE 100000;","output":"Sequence altered.","explain":{"ar":"ALTER SEQUENCE يغيّر خصائص التوليد المستقبلية فقط، لا الأرقام السابقة.","en":"ALTER SEQUENCE changes future generation behavior only, not previously generated numbers."},"mistake":{"ar":"لا يمكن تغيير START WITH بعد الإنشاء؛ يجب حذف الـSequence وإعادة إنشائه.","en":"START WITH cannot be changed after creation; the sequence must be dropped and recreated."}},{"cat":"objects","title":"CREATE SYNONYM","level":"متقدم","concept":{"ar":"إعطاء اسم بديل مختصر لكائن","en":"Giving an object a shorter alternate name"},"sql":"CREATE SYNONYM crs FOR courses;","output":"Synonym created.","explain":{"ar":"Synonym يسمح باستخدام اسم أقصر أو أوضح بدل الاسم الكامل للكائن.","en":"A synonym allows using a shorter or clearer name instead of the object full name."},"mistake":{"ar":"استخدام PUBLIC SYNONYM دون داعٍ يجعل الاسم البديل مرئيًا لكل المستخدمين.","en":"Using PUBLIC SYNONYM unnecessarily makes the alias visible to every user."}},{"cat":"objects","title":"CREATE INDEX","level":"مبتدئ","concept":{"ar":"تسريع البحث والفرز على عمود","en":"Speeding up search and sorting on a column"},"sql":"CREATE INDEX idx_students_name\nON students(full_name);","output":"Index created.","explain":{"ar":"الـIndex يبني بنية بحث سريعة، لكنه يضيف عبئًا بسيطًا على كل INSERT/UPDATE.","en":"An index builds a fast search structure but adds a small overhead to every INSERT/UPDATE."},"mistake":{"ar":"إنشاء Index على عمود نادرًا ما يُستخدم في WHERE يستهلك مساحة دون فائدة حقيقية.","en":"Creating an index on a column rarely used in WHERE wastes space with little real benefit."}},{"cat":"objects","title":"UNIQUE INDEX","level":"متوسط","concept":{"ar":"فهرس يمنع التكرار ويسرّع البحث معًا","en":"An index that both prevents duplicates and speeds search"},"sql":"CREATE UNIQUE INDEX idx_students_email\nON students(email);","output":"Index created.","explain":{"ar":"UNIQUE INDEX يجمع بين منع التكرار وتسريع البحث في بنية واحدة.","en":"A unique index combines duplicate prevention and faster search in one structure."},"mistake":{"ar":"إنشاء عدة Indexes على نفس الأعمدة تقريبًا يبطئ عمليات التعديل دون داعٍ.","en":"Creating several near-duplicate indexes on the same columns slows updates unnecessarily."}},{"cat":"joins","title":"INNER JOIN بجدولين","level":"مبتدئ","concept":{"ar":"دمج بيانات من جدولين حسب شرط مشترك","en":"Combining data from two tables via a shared condition"},"sql":"SELECT s.full_name, c.title\nFROM enrollments e\nJOIN students s ON e.student_id = s.student_id\nJOIN courses c ON e.course_id = c.course_id;","output":"FULL_NAME     TITLE\nLina Al-Amri  SQL Basics","explain":{"ar":"INNER JOIN يعرض فقط الصفوف التي لها تطابق في الجدولين معًا.","en":"INNER JOIN returns only rows that match in both tables."},"mistake":{"ar":"نسيان شرط ON بالكامل يحوّل الاستعلام إلى CROSS JOIN بدون قصد.","en":"Forgetting the ON condition entirely turns the query into an unintentional CROSS JOIN."}},{"cat":"joins","title":"JOIN مع WHERE إضافي","level":"متوسط","concept":{"ar":"تصفية نتيجة JOIN بشرط إضافي","en":"Filtering a JOIN result with an extra condition"},"sql":"SELECT e.first_name, d.department_name\nFROM employees e\nJOIN departments d ON e.department_id = d.department_id\nWHERE d.department_name = 'Sales';","output":"FIRST_NAME   DEPARTMENT_NAME\nOmar         Sales","explain":{"ar":"يمكن دمج JOIN وWHERE معًا: JOIN يربط الجداول، وWHERE يصفّي النتيجة.","en":"JOIN and WHERE can combine: JOIN links the tables, WHERE filters the result."},"mistake":{"ar":"وضع شرط الربط داخل WHERE بدل ON يعمل لكنه أقل وضوحًا في القراءة.","en":"Putting the join condition in WHERE instead of ON works but is less readable."}},{"cat":"joins","title":"JOIN ثلاثة جداول","level":"متقدم","concept":{"ar":"ربط أكثر من جدولين في استعلام واحد","en":"Linking more than two tables in one query"},"sql":"SELECT c.full_name, p.pname, i.total\nFROM customers c\nJOIN invoices i ON c.customer_id = i.customer_id\nJOIN invoice_details d ON i.invoice_id = d.invoice_id\nJOIN products p ON d.pid = p.pid;","output":"FULL_NAME    PNAME     TOTAL\nSara Nasser  Keyboard  120","explain":{"ar":"كل JOIN إضافي يربط جدولًا جديدًا بالسلسلة الموجودة عبر مفتاحه الخاص.","en":"Each additional JOIN links a new table to the existing chain via its own key."},"mistake":{"ar":"نسيان شرط ON لأحد الجداول الثلاثة يضخّم النتيجة بشكل غير منطقي.","en":"Forgetting the ON condition for one of the three tables inflates the result illogically."}},{"cat":"joins","title":"CROSS JOIN","level":"متوسط","concept":{"ar":"دمج كل صف من الجدول الأول مع كل صف من الثاني","en":"Combining every row of the first table with every row of the second"},"sql":"SELECT c.color, s.size_name\nFROM colors c\nCROSS JOIN sizes s;","output":"COLOR   SIZE_NAME\nRed     S\nRed     M\nBlue    S\nBlue    M","explain":{"ar":"النتيجة = عدد صفوف الجدول الأول × عدد صفوف الجدول الثاني.","en":"The result count equals rows in the first table times rows in the second."},"mistake":{"ar":"استخدام CROSS JOIN بالخطأ بدل INNER JOIN ينتج عددًا ضخمًا من الصفوف غير المفيدة.","en":"Accidentally using CROSS JOIN instead of INNER JOIN produces a huge number of useless rows."}},{"cat":"joins","title":"LEFT JOIN","level":"متوسط","concept":{"ar":"عرض كل صفوف الجدول الأيسر حتى بلا تطابق","en":"Showing all left-table rows even without a match"},"sql":"SELECT d.department_name, e.first_name\nFROM departments d\nLEFT JOIN employees e ON d.department_id = e.department_id;","output":"DEPARTMENT_NAME   FIRST_NAME\nSales             Omar\nHR                (null)","explain":{"ar":"LEFT JOIN يُبقي كل صفوف الجدول الأيسر، ويضع NULL لغير المتطابق من اليمين.","en":"LEFT JOIN keeps every left-table row, placing NULL for unmatched right-side rows."},"mistake":{"ar":"توقع نفس نتيجة INNER JOIN من LEFT JOIN يخفي أقسامًا بلا موظفين عن طريق الخطأ.","en":"Expecting LEFT JOIN to behave like INNER JOIN accidentally hides departments with no employees."}},{"cat":"joins","title":"RIGHT JOIN","level":"متوسط","concept":{"ar":"عرض كل صفوف الجدول الأيمن حتى بلا تطابق","en":"Showing all right-table rows even without a match"},"sql":"SELECT e.first_name, d.department_name\nFROM employees e\nRIGHT JOIN departments d ON e.department_id = d.department_id;","output":"FIRST_NAME   DEPARTMENT_NAME\nOmar         Sales\n(null)       HR","explain":{"ar":"RIGHT JOIN عكس LEFT JOIN: يُبقي كل صفوف الجدول الأيمن هذه المرة.","en":"RIGHT JOIN is the mirror of LEFT JOIN: it keeps every right-table row instead."},"mistake":{"ar":"يمكن دائمًا تحويل RIGHT JOIN إلى LEFT JOIN بعكس ترتيب الجدولين لتبسيط القراءة.","en":"A RIGHT JOIN can always be rewritten as a LEFT JOIN by swapping table order for clarity."}},{"cat":"joins","title":"FULL OUTER JOIN","level":"متقدم","concept":{"ar":"عرض كل الصفوف من الجدولين حتى بلا تطابق","en":"Showing all rows from both tables even without a match"},"sql":"SELECT e.first_name, d.department_name\nFROM employees e\nFULL OUTER JOIN departments d ON e.department_id = d.department_id;","output":"FIRST_NAME   DEPARTMENT_NAME\nOmar         Sales\n(null)       HR\nSara         (null)","explain":{"ar":"FULL OUTER JOIN يدمج نتيجة LEFT وRIGHT JOIN معًا في استعلام واحد.","en":"FULL OUTER JOIN combines the results of LEFT and RIGHT JOIN into one query."},"mistake":{"ar":"كثرة القيم NULL في النتيجة قد تربك القراءة إن لم تُفهم آلية FULL JOIN جيدًا.","en":"Many NULLs in the result can be confusing without understanding how FULL JOIN works."}},{"cat":"joins","title":"Self JOIN","level":"متقدم","concept":{"ar":"ربط جدول بنفسه لمقارنة صفوفه","en":"Joining a table with itself to compare its rows"},"sql":"SELECT e.first_name AS employee, m.first_name AS manager\nFROM employees e\nJOIN employees m ON e.manager_id = m.employee_id;","output":"EMPLOYEE   MANAGER\nOmar       Sara","explain":{"ar":"Self JOIN يستخدم Alias مختلفين لنفس الجدول للتفريق بين الدورين.","en":"A self join uses two different aliases for the same table to distinguish the roles."},"mistake":{"ar":"نسيان Alias مختلف لكل نسخة من الجدول يجعل الاستعلام غامضًا لأي عمود ينتمي.","en":"Forgetting distinct aliases for each table copy makes it unclear which column belongs where."}},{"cat":"joins","title":"JOIN مع دالة تجميع","level":"متقدم","concept":{"ar":"حساب إحصائية بعد ربط جدولين","en":"Computing an aggregate after joining two tables"},"sql":"SELECT d.department_name, COUNT(e.employee_id) AS total\nFROM departments d\nLEFT JOIN employees e ON d.department_id = e.department_id\nGROUP BY d.department_name;","output":"DEPARTMENT_NAME   TOTAL\nSales             1\nHR                0","explain":{"ar":"LEFT JOIN مع COUNT يُظهر حتى الأقسام التي لا تحتوي أي موظف (بقيمة 0).","en":"LEFT JOIN with COUNT shows even departments with zero employees."},"mistake":{"ar":"استخدام INNER JOIN هنا بدل LEFT JOIN يُسقط الأقسام الفارغة من النتيجة تمامًا.","en":"Using INNER JOIN here instead of LEFT JOIN drops empty departments entirely."}},{"cat":"joins","title":"JOIN باستخدام USING","level":"متوسط","concept":{"ar":"اختصار شرط الربط عندما يتطابق اسم العمود","en":"Shortening the join condition when column names match"},"sql":"SELECT s.full_name, c.title\nFROM enrollments e\nJOIN students s USING (student_id)\nJOIN courses c USING (course_id);","output":"FULL_NAME     TITLE\nLina Al-Amri  SQL Basics","explain":{"ar":"USING يُستخدم فقط عندما يحمل العمودان نفس الاسم في كلا الجدولين.","en":"USING works only when both tables share the exact same column name."},"mistake":{"ar":"محاولة استخدام USING مع أعمدة بأسماء مختلفة (مثل student_id وid) تسبب خطأ.","en":"Trying USING with differently named columns (e.g. student_id vs id) causes an error."}},{"cat":"joins","title":"NATURAL JOIN","level":"متقدم","concept":{"ar":"ربط تلقائي بالاعتماد على الأعمدة المتطابقة الاسم","en":"Automatic joining based on identically named columns"},"sql":"SELECT s.full_name, c.title\nFROM enrollments e\nNATURAL JOIN students s\nNATURAL JOIN courses c;","output":"FULL_NAME     TITLE\nLina Al-Amri  SQL Basics","explain":{"ar":"NATURAL JOIN يربط تلقائيًا بكل الأعمدة المشتركة الاسم بين الجدولين.","en":"NATURAL JOIN automatically links on every identically named shared column."},"mistake":{"ar":"وجود عمود مشترك الاسم غير مقصود (مثل created_at) يغيّر نتيجة الربط دون تحذير.","en":"An unintended shared column name (like created_at) silently changes the join result."}},{"cat":"joins","title":"JOIN مع LIKE في شرط الربط","level":"متقدم","concept":{"ar":"ربط جدولين بشرط مطابقة جزئية بدل التساوي","en":"Joining two tables on a partial match instead of equality"},"sql":"SELECT p.pname, k.keyword\nFROM products p\nJOIN product_keywords k ON p.pname LIKE '%' || k.keyword || '%';","output":"PNAME      KEYWORD\nKeyboard   board","explain":{"ar":"استخدام LIKE كشرط ربط مفيد للبحث الضبابي، لكنه أبطأ من التساوي المباشر.","en":"Using LIKE as a join condition suits fuzzy matching but is slower than direct equality."},"mistake":{"ar":"شروط LIKE المعقدة داخل JOIN قد تُبطئ الأداء بشكل كبير على جداول كبيرة.","en":"Complex LIKE conditions inside a JOIN can significantly slow performance on large tables."}},{"cat":"grouping","title":"GROUP BY أساسي","level":"مبتدئ","concept":{"ar":"تجميع الصفوف حسب قيمة عمود","en":"Grouping rows by a column value"},"sql":"SELECT department_id, COUNT(*) AS total\nFROM employees\nGROUP BY department_id;","output":"DEPARTMENT_ID   TOTAL\n10              3\n20              5","explain":{"ar":"كل عمود غير مُجمَّع عليه في SELECT يجب أن يكون داخل دالة تجميع.","en":"Every non-grouped column in SELECT must be wrapped in an aggregate function."},"mistake":{"ar":"وضع عمود في SELECT دون GROUP BY أو دالة تجميع يسبب خطأ مباشرة.","en":"Placing a column in SELECT without GROUP BY or an aggregate causes an immediate error."}},{"cat":"grouping","title":"HAVING بعد GROUP BY","level":"متوسط","concept":{"ar":"تصفية المجموعات بعد التجميع","en":"Filtering groups after aggregation"},"sql":"SELECT department_id, COUNT(*) AS total\nFROM employees\nGROUP BY department_id\nHAVING COUNT(*) >= 3;","output":"DEPARTMENT_ID   TOTAL\n20              5","explain":{"ar":"HAVING يعمل بعد التجميع، بعكس WHERE الذي يعمل قبل التجميع.","en":"HAVING runs after aggregation, unlike WHERE which runs before it."},"mistake":{"ar":"استخدام WHERE مع دالة تجميع مثل COUNT(*) بدل HAVING يسبب خطأ.","en":"Using WHERE with an aggregate like COUNT(*) instead of HAVING causes an error."}},{"cat":"grouping","title":"SUM مع GROUP BY","level":"متوسط","concept":{"ar":"حساب مجموع قيم لكل مجموعة","en":"Computing a sum per group"},"sql":"SELECT department_id, SUM(salary) AS total_salary\nFROM employees\nGROUP BY department_id;","output":"DEPARTMENT_ID   TOTAL_SALARY\n10              6200\n20              9300","explain":{"ar":"SUM يجمع قيم عمود رقمي داخل كل مجموعة على حدة.","en":"SUM adds up a numeric column values within each group separately."},"mistake":{"ar":"نسيان GROUP BY مع SUM يجمع كل الصفوف في رقم واحد فقط بدل مجموعة لكل قسم.","en":"Forgetting GROUP BY with SUM adds every row into one single number instead of per group."}},{"cat":"grouping","title":"AVG وROUND معًا","level":"متوسط","concept":{"ar":"حساب المتوسط وتقريبه لعدد منازل","en":"Computing an average and rounding it"},"sql":"SELECT department_id, ROUND(AVG(salary),1) AS avg_salary\nFROM employees\nGROUP BY department_id;","output":"DEPARTMENT_ID   AVG_SALARY\n10              6200.0\n20              5100.5","explain":{"ar":"ROUND حول AVG يجعل الرقم أوضح للقراءة بدل كسور عشرية طويلة.","en":"Wrapping AVG in ROUND makes the number cleaner instead of a long decimal."},"mistake":{"ar":"نسيان ROUND ليس خطأ، لكنه يجعل التقارير أقل احترافية بأرقام طويلة.","en":"Skipping ROUND is not an error, but it makes reports less polished with long decimals."}},{"cat":"grouping","title":"MIN وMAX معًا","level":"مبتدئ","concept":{"ar":"إيجاد أصغر وأكبر قيمة في عمود","en":"Finding the smallest and largest value in a column"},"sql":"SELECT MIN(salary) AS lowest, MAX(salary) AS highest\nFROM employees;","output":"LOWEST   HIGHEST\n4100     6200","explain":{"ar":"MIN وMAX يمكن استخدامهما معًا في نفس الاستعلام بلا GROUP BY إن أردت نتيجة عامة.","en":"MIN and MAX can be used together in one query without GROUP BY for an overall result."},"mistake":{"ar":"استخدامهما مع أعمدة أخرى غير مُجمَّعة دون GROUP BY يسبب خطأ.","en":"Using them with other non-aggregated columns without GROUP BY causes an error."}},{"cat":"grouping","title":"GROUP BY أكثر من عمود","level":"متقدم","concept":{"ar":"تجميع حسب أكثر من معيار معًا","en":"Grouping by more than one criterion together"},"sql":"SELECT department_id, job_title, COUNT(*) AS total\nFROM employees\nGROUP BY department_id, job_title;","output":"DEPARTMENT_ID   JOB_TITLE   TOTAL\n10              Analyst     2\n10              Manager     1","explain":{"ar":"التجميع بعمودين ينتج مجموعة لكل تركيبة فريدة منهما معًا.","en":"Grouping by two columns produces a group for each unique combination of both."},"mistake":{"ar":"توقع نتيجة مطابقة لتجميع عمود واحد فقط يجعل قراءة الجدول مربكة أول مرة.","en":"Expecting the same result as single-column grouping makes the table confusing at first."}},{"cat":"grouping","title":"HAVING بشرط على AVG","level":"متقدم","concept":{"ar":"عرض المجموعات التي متوسطها أعلى من حد معين","en":"Showing groups whose average exceeds a threshold"},"sql":"SELECT department_id, AVG(salary) AS avg_salary\nFROM employees\nGROUP BY department_id\nHAVING AVG(salary) > 5000;","output":"DEPARTMENT_ID   AVG_SALARY\n10              6200","explain":{"ar":"يمكن لـHAVING استخدام أي دالة تجميع، وليس COUNT فقط.","en":"HAVING can use any aggregate function, not only COUNT."},"mistake":{"ar":"كتابة HAVING salary > 5000 بدل AVG(salary) يسبب خطأ لأن salary غير مُجمَّع.","en":"Writing HAVING salary > 5000 instead of AVG(salary) errors because salary is not aggregated."}},{"cat":"grouping","title":"COUNT(DISTINCT)","level":"متقدم","concept":{"ar":"عدّ القيم الفريدة فقط داخل مجموعة","en":"Counting only unique values within a group"},"sql":"SELECT COUNT(DISTINCT department_id) AS dept_count\nFROM employees;","output":"DEPT_COUNT\n2","explain":{"ar":"COUNT(DISTINCT ...) يحسب القيم المختلفة فقط، متجاهلًا التكرار.","en":"COUNT(DISTINCT ...) counts only distinct values, ignoring duplicates."},"mistake":{"ar":"الخلط بين COUNT(*) وCOUNT(DISTINCT col) يعطي أرقامًا مختلفة تمامًا لنفس الجدول.","en":"Confusing COUNT(*) with COUNT(DISTINCT col) gives very different numbers for the same table."}},{"cat":"grouping","title":"GROUP BY مع ORDER BY","level":"متوسط","concept":{"ar":"ترتيب نتيجة التجميع","en":"Ordering an aggregated result"},"sql":"SELECT department_id, COUNT(*) AS total\nFROM employees\nGROUP BY department_id\nORDER BY total DESC;","output":"DEPARTMENT_ID   TOTAL\n20              5\n10              3","explain":{"ar":"يمكن الترتيب باسم العمود المستعار (Alias) الناتج من دالة التجميع مباشرة.","en":"You can order directly by the aggregate alias name."},"mistake":{"ar":"وضع ORDER BY قبل GROUP BY في الجملة يسبب خطأ Syntax لأن ترتيب البنود ثابت.","en":"Placing ORDER BY before GROUP BY in the statement causes a syntax error since clause order is fixed."}},{"cat":"grouping","title":"HAVING وWHERE معًا","level":"متقدم","concept":{"ar":"تصفية الصفوف قبل التجميع وبعده معًا","en":"Filtering rows both before and after aggregation"},"sql":"SELECT department_id, COUNT(*) AS total\nFROM employees\nWHERE hire_date > DATE '2020-01-01'\nGROUP BY department_id\nHAVING COUNT(*) >= 2;","output":"DEPARTMENT_ID   TOTAL\n20              3","explain":{"ar":"WHERE يستبعد الصفوف أولًا، ثم HAVING يصفّي المجموعات الناتجة بعد التجميع.","en":"WHERE excludes rows first, then HAVING filters the resulting groups after aggregation."},"mistake":{"ar":"محاولة وضع شرط hire_date داخل HAVING بدل WHERE يعمل لكنه أقل كفاءة.","en":"Putting the hire_date condition in HAVING instead of WHERE works but is less efficient."}},{"cat":"transactions","title":"COMMIT لتثبيت التغييرات","level":"مبتدئ","concept":{"ar":"حفظ التغييرات بشكل دائم في قاعدة البيانات","en":"Permanently saving changes to the database"},"sql":"UPDATE students SET gpa = 3.9 WHERE student_id = 1;\nCOMMIT;","output":"1 row updated.\nCommit complete.","explain":{"ar":"COMMIT يجعل التغييرات دائمة ومرئية لكل المستخدمين الآخرين.","en":"COMMIT makes changes permanent and visible to all other users."},"mistake":{"ar":"نسيان COMMIT يترك التغييرات معلّقة ويمكن أن تُفقد إذا انقطع الاتصال.","en":"Forgetting COMMIT leaves changes pending, and they can be lost if the connection drops."}},{"cat":"transactions","title":"ROLLBACK للتراجع","level":"مبتدئ","concept":{"ar":"التراجع عن تغييرات لم تُثبَّت بعد","en":"Undoing changes that have not yet been committed"},"sql":"DELETE FROM students WHERE student_id = 2;\nROLLBACK;","output":"1 row deleted.\nRollback complete.","explain":{"ar":"ROLLBACK يعيد البيانات إلى حالتها قبل بدء المعاملة الحالية.","en":"ROLLBACK restores data to its state before the current transaction began."},"mistake":{"ar":"تنفيذ COMMIT بالخطأ قبل ROLLBACK يجعل التراجع مستحيلًا بعد ذلك.","en":"Accidentally running COMMIT before ROLLBACK makes undoing impossible afterward."}},{"cat":"transactions","title":"SAVEPOINT للتراجع الجزئي","level":"متقدم","concept":{"ar":"وضع نقطة رجوع وسط معاملة طويلة","en":"Placing a return point in the middle of a long transaction"},"sql":"UPDATE students SET gpa = 4.0 WHERE student_id = 1;\nSAVEPOINT before_delete;\nDELETE FROM students WHERE student_id = 2;\nROLLBACK TO before_delete;","output":"1 row updated.\nSavepoint created.\n1 row deleted.\nRollback complete.","explain":{"ar":"ROLLBACK TO يتراجع فقط للنقطة المحددة، ويُبقي التغييرات قبلها.","en":"ROLLBACK TO reverts only to the named point, keeping changes made before it."},"mistake":{"ar":"نسيان اسم الـSavepoint الصحيح عند التراجع يسبب خطأ savepoint not found.","en":"Misremembering the savepoint name when rolling back causes a savepoint-not-found error."}},{"cat":"transactions","title":"معاملة كاملة متعددة الخطوات","level":"متقدم","concept":{"ar":"تجميع عدة أوامر DML كوحدة واحدة قابلة للتراجع","en":"Grouping several DML statements as one reversible unit"},"sql":"UPDATE students SET gpa = gpa - 0.1 WHERE student_id = 1;\nUPDATE students SET gpa = gpa + 0.1 WHERE student_id = 2;\nCOMMIT;","output":"1 row updated.\n1 row updated.\nCommit complete.","explain":{"ar":"تجميع خطوتين مترابطتين في معاملة واحدة يضمن تنفيذهما معًا أو عدم تنفيذ أي منهما.","en":"Grouping two related steps in one transaction ensures both run together or neither does."},"mistake":{"ar":"تنفيذ COMMIT بعد الخطوة الأولى فقط يكسر ترابط العملية المقصودة.","en":"Committing after only the first step breaks the intended atomicity of the operation."}},{"cat":"transactions","title":"التحقق قبل COMMIT","level":"متوسط","concept":{"ar":"مراجعة النتيجة عبر SELECT قبل تثبيت التغيير","en":"Reviewing the result via SELECT before committing"},"sql":"UPDATE students SET gpa = 3.5 WHERE student_id = 3;\nSELECT * FROM students WHERE student_id = 3;\nCOMMIT;","output":"1 row updated.\nSTUDENT_ID  GPA\n3           3.5\nCommit complete.","explain":{"ar":"يمكن الاطلاع على نتيجة التعديل قبل COMMIT للتأكد من صحته داخل نفس الجلسة.","en":"You can review the update result before COMMIT to confirm correctness within the same session."},"mistake":{"ar":"الاعتماد فقط على الثقة دون مراجعة السطر المعدَّل قد يثبّت خطأ بالخطأ.","en":"Trusting the update blindly without reviewing it may commit a mistake unintentionally."}},{"cat":"transactions","title":"ROLLBACK بعد خطأ متعدد الصفوف","level":"متقدم","concept":{"ar":"التراجع الفوري بعد اكتشاف نتيجة غير متوقعة","en":"Rolling back immediately after spotting an unexpected result"},"sql":"UPDATE students SET gpa = 0;\n-- لاحظت أن كل الصفوف تغيّرت بالخطأ\nROLLBACK;","output":"3 rows updated.\nRollback complete.","explain":{"ar":"ROLLBACK قبل COMMIT هو خط الدفاع الأخير عند تنفيذ UPDATE بلا WHERE بالخطأ.","en":"ROLLBACK before COMMIT is the last line of defense after an accidental unconditional UPDATE."},"mistake":{"ar":"التردد أو تنفيذ أوامر أخرى قبل ROLLBACK قد يؤدي لـCOMMIT تلقائي في بعض الإعدادات.","en":"Hesitating or running other commands before ROLLBACK may trigger an automatic commit in some setups."}},{"cat":"transactions","title":"SAVEPOINT متعدد","level":"متقدم","concept":{"ar":"استخدام أكثر من نقطة رجوع في نفس المعاملة","en":"Using more than one return point in the same transaction"},"sql":"SAVEPOINT sp1;\nUPDATE students SET gpa = 3.0 WHERE student_id = 1;\nSAVEPOINT sp2;\nUPDATE students SET gpa = 2.0 WHERE student_id = 1;\nROLLBACK TO sp1;","output":"Savepoint created.\n1 row updated.\nSavepoint created.\n1 row updated.\nRollback complete.","explain":{"ar":"التراجع إلى sp1 يلغي كلا التحديثين، بينما التراجع إلى sp2 كان سيلغي الثاني فقط.","en":"Rolling back to sp1 cancels both updates, while rolling back to sp2 would cancel only the second."},"mistake":{"ar":"نسيان ترتيب الـSavepoints يؤدي لتراجع أكبر أو أصغر من المقصود.","en":"Losing track of savepoint order leads to rolling back more or less than intended."}},{"cat":"transactions","title":"التزام ضمني عند DDL","level":"متقدم","concept":{"ar":"فهم أن أوامر DDL تُثبّت المعاملة تلقائيًا","en":"Understanding that DDL commands auto-commit the transaction"},"sql":"UPDATE students SET gpa = 3.9 WHERE student_id = 1;\nCREATE TABLE temp_log (msg VARCHAR2(50));\n-- التحديث السابق أصبح مثبتًا تلقائيًا الآن","output":"1 row updated.\nTable TEMP_LOG created.","explain":{"ar":"أي أمر DDL مثل CREATE أو ALTER يُنفّذ COMMIT ضمنيًا لأي DML سابق لم يُثبَّت بعد.","en":"Any DDL command like CREATE or ALTER implicitly commits any prior uncommitted DML."},"mistake":{"ar":"الاعتقاد أن ROLLBACK سيلغي تحديثًا سبقه أمر DDL خطأ شائع وخطير.","en":"Believing ROLLBACK can undo an update that a DDL command already followed is a common, risky mistake."}},{"cat":"errors","title":"ORA-00001: unique constraint","level":"مبتدئ","concept":{"ar":"محاولة إدخال قيمة مكررة في عمود فريد","en":"Attempting to insert a duplicate value into a unique column"},"sql":"INSERT INTO students (student_id, full_name)\nVALUES (1, 'Another Name');","output":"ORA-00001: unique constraint violated","explain":{"ar":"الخطأ يظهر لأن student_id=1 موجود مسبقًا في الجدول.","en":"The error appears because student_id=1 already exists in the table."},"mistake":{"ar":"الحل: تحقق أولًا بـSELECT من عدم وجود القيمة، أو استخدم Sequence لتوليدها.","en":"Fix: check with SELECT first that the value does not exist, or use a sequence to generate it."}},{"cat":"errors","title":"ORA-01400: cannot insert NULL","level":"مبتدئ","concept":{"ar":"محاولة ترك عمود NOT NULL فارغًا","en":"Attempting to leave a NOT NULL column empty"},"sql":"INSERT INTO students (student_id, full_name)\nVALUES (5, NULL);","output":"ORA-01400: cannot insert NULL","explain":{"ar":"full_name معرّف كـNOT NULL، فلا يقبل قيمة فارغة عند الإدخال.","en":"full_name is defined NOT NULL, so it rejects an empty value on insert."},"mistake":{"ar":"الحل: تأكد من توفر قيمة حقيقية لكل عمود NOT NULL قبل التنفيذ.","en":"Fix: ensure a real value is supplied for every NOT NULL column before executing."}},{"cat":"errors","title":"ORA-02291: parent key not found","level":"متوسط","concept":{"ar":"إدخال قيمة FOREIGN KEY غير موجودة في الجدول الأب","en":"Inserting a foreign key value not present in the parent table"},"sql":"INSERT INTO enrollments (student_id, course_id)\nVALUES (999, 1);","output":"ORA-02291: integrity constraint violated - parent key not found","explain":{"ar":"لا يوجد طالب برقم 999 في جدول students، فيرفض القيد إدخال هذا الربط.","en":"No student with id 999 exists in students, so the constraint rejects this link."},"mistake":{"ar":"الحل: أدخل الطالب أولًا في الجدول الأب، أو تحقق من رقمه قبل الربط.","en":"Fix: insert the student in the parent table first, or verify the id before linking."}},{"cat":"errors","title":"ORA-02292: child record found","level":"متوسط","concept":{"ar":"محاولة حذف صف أب له صفوف تابعة","en":"Attempting to delete a parent row that has dependent rows"},"sql":"DELETE FROM students WHERE student_id = 1;","output":"ORA-02292: integrity constraint violated - child record found","explain":{"ar":"يوجد صف في enrollments يشير إلى هذا الطالب، فيمنع الحذف حماية للترابط.","en":"A row in enrollments references this student, so deletion is blocked to protect referential integrity."},"mistake":{"ar":"الحل: احذف الصفوف التابعة أولًا، أو استخدم ON DELETE CASCADE عند تصميم القيد.","en":"Fix: delete dependent rows first, or design the constraint with ON DELETE CASCADE."}},{"cat":"errors","title":"ORA-00904: invalid identifier","level":"مبتدئ","concept":{"ar":"استخدام اسم عمود غير موجود أو مكتوب خطأ","en":"Using a column name that does not exist or is misspelled"},"sql":"SELECT studnet_id FROM students;","output":"ORA-00904: invalid identifier","explain":{"ar":"اسم العمود مكتوب خطأ (studnet بدل student)، فلا يجده Oracle.","en":"The column name is misspelled (studnet instead of student), so Oracle cannot find it."},"mistake":{"ar":"الحل: راجع أسماء الأعمدة بدقة، أو استخدم DESCRIBE لعرض الأعمدة الصحيحة.","en":"Fix: double-check column names, or use DESCRIBE to list the correct columns."}},{"cat":"errors","title":"ORA-00942: table or view does not exist","level":"مبتدئ","concept":{"ar":"الاستعلام عن جدول محذوف أو اسمه خطأ","en":"Querying a table that was dropped or misnamed"},"sql":"SELECT * FROM student;","output":"ORA-00942: table or view does not exist","explain":{"ar":"اسم الجدول الصحيح هو students (بصيغة الجمع)، وليس student.","en":"The correct table name is students (plural), not student."},"mistake":{"ar":"الحل: تحقق من الاسم الصحيح، أو تأكد أن الجدول لم يُحذف بواسطة DROP TABLE.","en":"Fix: verify the correct name, or confirm the table was not removed by DROP TABLE."}},{"cat":"errors","title":"ORA-00936: missing expression","level":"مبتدئ","concept":{"ar":"كتابة جملة SQL ناقصة العناصر","en":"Writing an incomplete SQL statement"},"sql":"SELECT FROM students;","output":"ORA-00936: missing expression","explain":{"ar":"نسيان تحديد الأعمدة أو * بعد SELECT يجعل الجملة غير مكتملة نحويًا.","en":"Forgetting to specify columns or * after SELECT makes the statement grammatically incomplete."},"mistake":{"ar":"الحل: أضف اسم عمود واحد على الأقل أو * مباشرة بعد SELECT.","en":"Fix: add at least one column name or * right after SELECT."}},{"cat":"errors","title":"ORA-01722: invalid number","level":"متوسط","concept":{"ar":"مقارنة أو تحويل نص إلى رقم بشكل غير صالح","en":"Comparing or converting invalid text to a number"},"sql":"SELECT * FROM students\nWHERE gpa = 'excellent';","output":"ORA-01722: invalid number","explain":{"ar":"gpa عمود رقمي، فمقارنته بنص مثل excellent تفشل التحويل الضمني.","en":"gpa is numeric, so comparing it to text like excellent fails implicit conversion."},"mistake":{"ar":"الحل: قارن الأعمدة الرقمية بقيم رقمية فقط، أو استخدم CASE للتصنيف النصي.","en":"Fix: compare numeric columns only to numeric values, or use CASE for text categorization."}},{"cat":"errors","title":"ORA-00933: SQL command not properly ended","level":"مبتدئ","concept":{"ar":"ترتيب بنود الاستعلام بشكل خاطئ","en":"Placing query clauses in the wrong order"},"sql":"SELECT * FROM students\nORDER BY gpa\nWHERE gpa > 3;","output":"ORA-00933: SQL command not properly ended","explain":{"ar":"WHERE يجب أن يسبق ORDER BY دائمًا، وليس العكس.","en":"WHERE must always come before ORDER BY, never after."},"mistake":{"ar":"الحل: احفظ ترتيب البنود الثابت: SELECT ثم FROM ثم WHERE ثم GROUP BY ثم HAVING ثم ORDER BY.","en":"Fix: remember the fixed clause order: SELECT, FROM, WHERE, GROUP BY, HAVING, ORDER BY."}},{"cat":"errors","title":"single-row subquery returns more than one row","level":"متقدم","concept":{"ar":"استخدام = مع Subquery يعيد أكثر من صف","en":"Using = with a subquery that returns more than one row"},"sql":"SELECT first_name FROM employees\nWHERE department_id = (\n  SELECT department_id FROM departments WHERE location LIKE '%Main%'\n);","output":"ORA-01427: single-row subquery returns more than one row","explain":{"ar":"الـSubquery أعاد أكثر من قسم واحد، لكن = يتوقع قيمة واحدة فقط.","en":"The subquery returned more than one department, but = expects only a single value."},"mistake":{"ar":"الحل: استبدل = بـIN عندما يُتوقع أن يعيد الـSubquery أكثر من صف.","en":"Fix: replace = with IN when the subquery may return multiple rows."}}];
window.SQL_EXAMPLE_CATS = [{"id":"select","ar":"SELECT وWHERE","en":"SELECT & WHERE"},{"id":"ddl","ar":"DDL","en":"DDL"},{"id":"dml","ar":"DML","en":"DML"},{"id":"dcl","ar":"DCL","en":"DCL"},{"id":"constraints","ar":"Constraints","en":"Constraints"},{"id":"objects","ar":"Views/Sequences/Synonyms/Indexes","en":"Views/Sequences/Synonyms/Indexes"},{"id":"joins","ar":"JOIN","en":"JOIN"},{"id":"grouping","ar":"GROUP BY وHAVING","en":"GROUP BY & HAVING"},{"id":"transactions","ar":"Transactions","en":"Transactions"},{"id":"errors","ar":"أخطاء شائعة","en":"Common Errors"}];
